Window.Script:
function form_OnLoadCompleted(obj)
{
    ButtonSave.Enable = false;
    fnToggleDetail();
}

function EditLotId_OnChanged(obj)
{
    if (obj.Text != "") ButtonSave.Enable = true;
    if (obj.Text != "") StaticStatus.Text = "입력 완료";
}

function fnToggleDetail()
{
    if (ds_result.getRowCount() == 0) DivDetail.Visible = false;
}

function fnSave()
{
    if (EditLotId.Text == "") {
        alert("LOT ID는 필수입니다.");
        return false;
    }

    if (!isNumber(EditQty.Text)) {
        alert("수량은 숫자여야 합니다.");
        return false;
    }

    if (String(EditRemark.Text).length > 100) {
        alert("비고는 100자 이하여야 합니다.");
        return false;
    }

    if (!confirm("저장하시겠습니까?")) {
        return false;
    }

    transaction("saveLot", "/api/lot/save", "", "ds_result=ds_output", "", "fnCallback");
}

function fnCallback(svcid, errorCode, errorMsg)
{
    if (errorCode != 0) {
        alert(errorMsg);
    }
}
